public static void main(Args args)
{
    var builder = DBMSQLQueryStoreWaitStatsViewBuilder::construct();
    builder.createSqlObjects();
}

private str createViewSqlStmt()
{
    str sqlStmt = 'CREATE VIEW ' + viewName + ' AS ' + this.createSQLStatement();
    return sqlStmt;
}

protected void initialize(boolean _runOnSeparateUserConnection = false)
{
    super(_runOnSeparateUserConnection);

    SysDictView view    = new SysDictView(tableNum(DBMSQLQueryStoreWaitStats));
    viewName            = view.name(DbBackend::Sql);
    asWaitStatsId = view.fieldObject(fieldNum(DBMSQLQueryStoreWaitStats, WaitStatsId)).name(DbBackend::Sql);
    asPlanId = view.fieldObject(fieldNum(DBMSQLQueryStoreWaitStats, PlanId)).name(DbBackend::Sql);
    asRuntimeStatsIntervalId = view.fieldObject(fieldNum(DBMSQLQueryStoreWaitStats, RuntimeStatsIntervalId)).name(DbBackend::Sql);
    asWaitCategory = view.fieldObject(fieldNum(DBMSQLQueryStoreWaitStats, WaitCategory)).name(DbBackend::Sql);
    asWaitCategoryDesc = view.fieldObject(fieldNum(DBMSQLQueryStoreWaitStats, WaitCategoryDesc)).name(DbBackend::Sql);
    asExecutionType = view.fieldObject(fieldNum(DBMSQLQueryStoreWaitStats, ExecutionType)).name(DbBackend::Sql);
    asExecutionTypeDesc = view.fieldObject(fieldNum(DBMSQLQueryStoreWaitStats, ExecutionTypeDesc)).name(DbBackend::Sql);
    asTotalQueryWaitTimeMs = view.fieldObject(fieldNum(DBMSQLQueryStoreWaitStats, TotalQueryWaitTimeMs)).name(DbBackend::Sql);
    asAvgQueryWaitTimeMs = view.fieldObject(fieldNum(DBMSQLQueryStoreWaitStats, AvgQueryWaitTimeMs)).name(DbBackend::Sql);
    asLastQueryWaitTimeMs = view.fieldObject(fieldNum(DBMSQLQueryStoreWaitStats, LastQueryWaitTimeMs)).name(DbBackend::Sql);
    asMinQueryWaitTimeMs = view.fieldObject(fieldNum(DBMSQLQueryStoreWaitStats, MinQueryWaitTimeMs)).name(DbBackend::Sql);
    asMaxQueryWaitTimeMs = view.fieldObject(fieldNum(DBMSQLQueryStoreWaitStats, MaxQueryWaitTimeMs)).name(DbBackend::Sql);
    asStdevQueryWaitTimeMs = view.fieldObject(fieldNum(DBMSQLQueryStoreWaitStats, StdevQueryWaitTimeMs)).name(DbBackend::Sql);
    asReplicaGroupId = view.fieldObject(fieldNum(DBMSQLQueryStoreWaitStats, ReplicaGroupId)).name(DbBackend::Sql);
    asRecId = view.fieldObject(fieldNum(DBMSQLQueryStoreWaitStats, RecId)).name(DbBackend::Sql);
}

public static DBMSQLQueryStoreWaitStatsViewBuilder construct()
{
    return new DBMSQLQueryStoreWaitStatsViewBuilder();
}
